package com.socialblog.notification.api;import jakarta.servlet.http.HttpServletRequest;import org.springframework.http.*;import org.springframework.web.bind.annotation.*;import java.time.Instant;import java.util.Map;@RestControllerAdvice public class GlobalExceptionHandler{public record Error(Instant timestamp,int status,String code,String message,String path,Map<String,String>fields){}@ExceptionHandler(ApiException.class)ResponseEntity<Error>api(ApiException e,HttpServletRequest r){return ResponseEntity.status(e.status()).body(new Error(Instant.now(),e.status().value(),e.code(),e.getMessage(),r.getRequestURI(),Map.of()));}}
